-- {"operators": "INNER_JOIN,AGGREGATE,FILTER,HAVING,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "WAREHOUSE,DISTRICT,CUSTOMER,OORDER", "ducklake": true}
WITH big_districts AS (SELECT D_W_ID, D_ID FROM dl.DISTRICT WHERE D_YTD > 1000) SELECT bd.D_W_ID, bd.D_ID, COUNT(o.O_ID) AS orders FROM big_districts bd JOIN dl.WAREHOUSE w ON bd.D_W_ID = w.W_ID JOIN dl.CUSTOMER c ON bd.D_W_ID = c.C_W_ID AND bd.D_ID = c.C_D_ID JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID GROUP BY bd.D_W_ID, bd.D_ID HAVING COUNT(o.O_ID) > 0;
